2159   bool RewriteGEPs = !Base.LHSGEPs.empty() && !Base.RHSGEPs.empty();
2160 
2161   Type *IdxTy = DL.getIndexType(LHS->getType());
2162   Value *Result = EmitGEPOffsets(Base.LHSGEPs, Base.LHSNW, IdxTy, RewriteGEPs);
2163   Value *Offset2 = EmitGEPOffsets(Base.RHSGEPs, Base.RHSNW, IdxTy, RewriteGEPs);
2164 
2165   // If this is a single inbounds GEP and the original sub was nuw,
2166   // then the final multiplication is also nuw.
2167   if (auto *I = dyn_cast<Instruction>(Result))
2168     if (IsNUW && match(Offset2, m_Zero()) && Base.LHSNW.isInBounds() &&
