2259     }
2260 
2261     return Res;
2262   }
2263 
2264   // Try this before Negator to preserve NSW flag.
2265   if (Instruction *R = factorizeMathWithShlOps(I, Builder))
2266     return R;
2267 
2268   Constant *C;
2269   if (match(Op0, m_ImmConstant(C))) {
2270     Value *X;
2271     Constant *C2;
2272 
2273     // C-(X+C2) --> (C-C2)-X
2274     if (match(Op1, m_Add(m_Value(X), m_ImmConstant(C2)))) {
2275       // C-C2 never overflow, and C-(X+C2), (X+C2) has NSW/NUW
2276       // => (C-C2)-X can have NSW/NUW
2277       bool WillNotSOV = willNotOverflowSignedSub(C, C2, I);
2278       BinaryOperator *Res =
2279           BinaryOperator::CreateSub(ConstantExpr::getSub(C, C2), X);
2280       auto *OBO1 = cast<OverflowingBinaryOperator>(Op1);
2281       Res->setHasNoSignedWrap(I.hasNoSignedWrap() && OBO1->hasNoSignedWrap() &&
2282                               WillNotSOV);
2283       Res->setHasNoUnsignedWrap(I.hasNoUnsignedWrap() &&
2284                                 OBO1->hasNoUnsignedWrap());
2285       return Res;
2286     }
2287   }
2288 
2289   auto TryToNarrowDeduceFlags = [this, &I, &Op0, &Op1]() -> Instruction * {
2290     if (Instruction *Ext = narrowMathIfNoOverflow(I))
2291       return Ext;
2292 
2293     bool Changed = false;
2294     if (!I.hasNoSignedWrap() && willNotOverflowSignedSub(Op0, Op1, I)) {
2295       Changed = true;
2296       I.setHasNoSignedWrap(true);
2297     }
2298     if (!I.hasNoUnsignedWrap() && willNotOverflowUnsignedSub(Op0, Op1, I)) {
2299       Changed = true;
2300       I.setHasNoUnsignedWrap(true);
2301     }
2302 
2303     return Changed ? &I : nullptr;
2304   };
2305 
2306   // First, let's try to interpret `sub a, b` as `add a, (sub 0, b)`,
2307   // and let's try to sink `(sub 0, b)` into `b` itself. But only if this isn't
2308   // a pure negation used by a select that looks like abs/nabs.
2309   bool IsNegation = match(Op0, m_ZeroInt());
2310   if (!IsNegation || none_of(I.users(), [&I, Op1](const User *U) {
2311         const Instruction *UI = dyn_cast<Instruction>(U);
2312         if (!UI)
2313           return false;
2314         return match(UI, m_c_Select(m_Specific(Op1), m_Specific(&I)));
2315       })) {
2316     if (Value *NegOp1 = Negator::Negate(IsNegation, /* IsNSW */ IsNegation &&
2317                                                         I.hasNoSignedWrap(),
2318                                         Op1, *this))
2319       return BinaryOperator::CreateAdd(NegOp1, Op0);
2320   }
2321   if (IsNegation)
2322     return TryToNarrowDeduceFlags(); // Should have been handled in Negator!
2323 
2324   // (A*B)-(A*C) -> A*(B-C) etc
2325   if (Value *V = foldUsingDistributiveLaws(I))
2326     return replaceInstUsesWith(I, V);
2327 
2328   if (I.getType()->isIntOrIntVectorTy(1))
2329     return BinaryOperator::CreateXor(Op0, Op1);
2330 
2331   // Replace (-1 - A) with (~A).
2332   if (match(Op0, m_AllOnes()))
2333     return BinaryOperator::CreateNot(Op1);
2334 
2335   // (X + -1) - Y --> ~Y + X
2336   Value *X, *Y;
2337   if (match(Op0, m_OneUse(m_Add(m_Value(X), m_AllOnes()))))
2338     return BinaryOperator::CreateAdd(Builder.CreateNot(Op1), X);
2339 
2340   // if (C1 & C2) == C2 then (X & C1) - (X & C2) -> X & (C1 ^ C2)
2341   Constant *C1, *C2;
2342   if (match(Op0, m_And(m_Value(X), m_ImmConstant(C1))) &&
2343       match(Op1, m_And(m_Specific(X), m_ImmConstant(C2)))) {
2344     Value *AndC = ConstantFoldBinaryInstruction(Instruction::And, C1, C2);
2345     if (C2->isElementWiseEqual(AndC))
2346       return BinaryOperator::CreateAnd(
2347           X, ConstantFoldBinaryInstruction(Instruction::Xor, C1, C2));
2348   }
